INSERT INTO public.agency_policy_settings (id, section_key, section_title, content, display_order, is_active, created_at, updated_at) VALUES ('12345678-abcd-4def-89ab-cdef01234567', 'penalties', 'জরিমানা ও শাস্তি', '{"items":["নিয়ম ভঙ্গ করলে সতর্কতা দেওয়া হবে","বারবার নিয়ম ভঙ্গ করলে এজেন্সি সাসপেন্ড হতে পারে","প্রতারণামূলক কার্যক্রমে এজেন্সি স্থায়ীভাবে বন্ধ হবে","হোস্টদের সাথে অসদাচরণ করলে ব্যবস্থা নেওয়া হবে"]}', '3', 't', '2026-01-31 05:03:10.757039+00', '2026-01-31 05:03:10.757039+00') ON CONFLICT DO NOTHING;
INSERT INTO public.agency_policy_settings (id, section_key, section_title, content, display_order, is_active, created_at, updated_at) VALUES ('abcd1234-5678-4abc-def0-123456789abc', 'benefits', 'সুবিধাসমূহ', '{"items":["এজেন্সি ড্যাশবোর্ড অ্যাক্সেস","হোস্ট পারফরম্যান্স ট্র্যাকিং","সাপ্তাহিক ও মাসিক রিপোর্ট","প্রিমিয়াম সাপোর্ট"]}', '4', 't', '2026-01-31 05:03:10.757039+00', '2026-01-31 05:03:10.757039+00') ON CONFLICT DO NOTHING;
INSERT INTO public.agency_policy_settings (id, section_key, section_title, content, display_order, is_active, created_at, updated_at) VALUES ('def01234-5678-4abc-def0-abcdef012345', 'withdrawal', 'উইথড্র নীতি', '{"items":["প্রতিদিন সর্বোচ্চ একবার উইথড্র করা যাবে","ন্যূনতম উইথড্র পরিমাণ ১০০ ডায়মন্ড","উইথড্র প্রসেসিং সময় ১-৩ কার্যদিবস","শুধুমাত্র যাচাইকৃত পেমেন্ট মেথডে উইথড্র সম্ভব"]}', '5', 't', '2026-01-31 05:03:10.757039+00', '2026-01-31 05:03:10.757039+00') ON CONFLICT DO NOTHING;
INSERT INTO public.agency_policy_settings (id, section_key, section_title, content, display_order, is_active, created_at, updated_at) VALUES ('98765432-abcd-4def-89ab-cdef98765432', 'host_management', 'হোস্ট ম্যানেজমেন্ট', '{"items":["এজেন্সি সর্বোচ্চ ১০০ জন হোস্ট রাখতে পারবে","প্রতিটি হোস্টকে ভেরিফাই করা আবশ্যক","হোস্ট পারফরম্যান্স মনিটরিং করতে হবে","নন-পারফর্মিং হোস্টদের সতর্ক করা হবে"]}', '6', 't', '2026-01-31 05:03:10.757039+00', '2026-01-31 05:03:10.757039+00') ON CONFLICT DO NOTHING;
